// Next Greater Element — O(n) with monotonic stack
int[] nextGreater(int[] nums) {
    int n = nums.length;
    int[] result = new int[n];
    Arrays.fill(result, -1);
    Deque<Integer> stack = new ArrayDeque<>(); // stores indices

    for (int i = 0; i < n; i++) {
        // pop all elements smaller than nums[i]
        while (!stack.isEmpty() && nums[stack.peek()] < nums[i]) {
            result[stack.pop()] = nums[i];
        }
        stack.push(i);
    }
    return result;
}

class UnionFind {
    int[] parent, rank;

    UnionFind(int n) {
        parent = new int[n];
        rank   = new int[n];
        for (int i = 0; i < n; i++) parent[i] = i;
    }

    int find(int x) { // path compression
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    boolean union(int a, int b) { // union by rank
        int ra = find(a), rb = find(b);
        if (ra == rb) return false; // already same set (cycle!)
        if (rank[ra] < rank[rb]) parent[ra] = rb;
        else if (rank[ra] > rank[rb]) parent[rb] = ra;
        else { parent[rb] = ra; rank[ra]++; }
        return true;
    }
}

// Kahn's Algorithm (BFS-based)
List<Integer> topoSort(int n, int[][] edges) {
    int[] inDegree = new int[n];
    List<List<Integer>> adj = new ArrayList<>();
    for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
    for (int[] e : edges) { adj.get(e[0]).add(e[1]); inDegree[e[1]]++; }

    Queue<Integer> q = new LinkedList<>();
    for (int i = 0; i < n; i++) if (inDegree[i] == 0) q.add(i);

    List<Integer> order = new ArrayList<>();
    while (!q.isEmpty()) {
        int node = q.poll();
        order.add(node);
        for (int nei : adj.get(node))
            if (--inDegree[nei] == 0) q.add(nei);
    }
    return order.size() == n ? order : List.of(); // empty = cycle
}

class TrieNode {
    TrieNode[] children = new TrieNode[26];
    boolean isEnd;
}

class Trie {
    TrieNode root = new TrieNode();

    void insert(String word) {
        TrieNode cur = root;
        for (char c : word.toCharArray()) {
            int i = c - 'a';
            if (cur.children[i] == null) cur.children[i] = new TrieNode();
            cur = cur.children[i];
        }
        cur.isEnd = true;
    }

    boolean startsWith(String prefix) {
        TrieNode cur = root;
        for (char c : prefix.toCharArray()) {
            int i = c - 'a';
            if (cur.children[i] == null) return false;
            cur = cur.children[i];
        }
        return true; // prefix exists
    }
}

int maxSubArray(int[] nums) {
    int maxSoFar = nums[0], globalMax = nums[0];
    for (int i = 1; i < nums.length; i++) {
        maxSoFar = Math.max(nums[i], maxSoFar + nums[i]);
        globalMax = Math.max(globalMax, maxSoFar);
    }
    return globalMax;
}

class LRUCache {
    int capacity;
    LinkedHashMap<Integer, Integer> cache;

    LRUCache(int capacity) {
        this.capacity = capacity;
        // accessOrder=true: move accessed entries to the end
        cache = new LinkedHashMap<>(16, 0.75f, true) {
            protected boolean removeEldestEntry(Map.Entry eldest) {
                return size() > capacity; // auto-evict LRU
            }
        };
    }

    int get(int key) { return cache.getOrDefault(key, -1); }
    void put(int key, int value) { cache.put(key, value); }
}

// Find start of cycle in linked list
ListNode detectCycleStart(ListNode head) {
    ListNode slow = head, fast = head;
    // Phase 1: find meeting point
    while (fast != null && fast.next != null) {
        slow = slow.next;
        fast = fast.next.next;
        if (slow == fast) break; // cycle found
    }
    if (fast == null || fast.next == null) return null; // no cycle
    // Phase 2: find cycle entry
    slow = head;
    while (slow != fast) { slow = slow.next; fast = fast.next; }
    return slow; // cycle start
}
